// Core scaffold generators ("af core new").
//
// All inline templates carry a `Generated by AccelFury IP Toolchain` stamp
// applied via the helpers at the top. Byte-determinism of the produced files
// is enforced by `crates/af-cli/tests/cli.rs::core_new_output_is_byte_deterministic_*`.

use crate::{parse_project_class, write_new_file, CliError, CliOutput};
use af_complexity::{PortabilityLevel, ProjectClass};
use af_manifest::{CoreManifest, CoreMaturity, CorePriority};
use serde_json::json;
use std::fs;
use std::path::{Path, PathBuf};
use std::str::FromStr;

/// User-supplied overrides for manifesto axes. Each `Some(...)` replaces the
/// profile default in the generated manifest; `None` leaves the default
/// untouched.
#[derive(Clone, Debug, Default)]
pub struct AxesOverride {
    pub portability_level: Option<PortabilityLevel>,
    pub priority: Option<CorePriority>,
    pub maturity: Option<CoreMaturity>,
}

impl AxesOverride {
    pub fn from_cli(
        portability_level: Option<&str>,
        priority: Option<&str>,
        maturity: Option<&str>,
    ) -> Result<Self, CliError> {
        fn parse_axis<T: FromStr<Err = E>, E: std::fmt::Display>(
            value: Option<&str>,
            field: &str,
        ) -> Result<Option<T>, CliError> {
            value
                .map(|raw| {
                    raw.parse::<T>().map_err(|err| {
                        CliError::new(
                            "AF_CORE_NEW_AXIS_INVALID",
                            format!("--{field} `{raw}` is invalid: {err}"),
                            "Use one of the allowed axis values; see docs/manifest-reference.md.",
                            2,
                        )
                    })
                })
                .transpose()
        }
        Ok(Self {
            portability_level: parse_axis::<PortabilityLevel, _>(
                portability_level,
                "portability-level",
            )?,
            priority: parse_axis::<CorePriority, _>(priority, "priority")?,
            maturity: parse_axis::<CoreMaturity, _>(maturity, "maturity")?,
        })
    }

    pub fn is_empty(&self) -> bool {
        self.portability_level.is_none() && self.priority.is_none() && self.maturity.is_none()
    }
}

pub const GENERATED_CORE_LICENSE_NAME: &str = "AccelFury Source Available License v1.0";
pub const GENERATED_CORE_SPDX_LICENSE_REF: &str = "LicenseRef-AccelFury-Source-Available-1.0";
pub const GENERATED_BY_MARKER: &str = "Generated by AccelFury IP Toolchain";

pub fn stamp_toml(content: impl Into<String>) -> String {
    format!("# {GENERATED_BY_MARKER}\n{}", content.into())
}

pub fn stamp_verilog(content: impl Into<String>) -> String {
    let content = content.into();
    // Preserve SPDX header if present: insert the stamp on the line AFTER SPDX
    // so license scanners still see SPDX-License-Identifier as the first line.
    if let Some(rest) = content.strip_prefix("// SPDX-License-Identifier:") {
        if let Some(newline_idx) = rest.find('\n') {
            let (spdx_tail, rest_after_spdx) = rest.split_at(newline_idx + 1);
            return format!(
                "// SPDX-License-Identifier:{spdx_tail}// {GENERATED_BY_MARKER}\n{rest_after_spdx}"
            );
        }
    }
    format!("// {GENERATED_BY_MARKER}\n{content}")
}

pub fn stamp_markdown(content: impl Into<String>) -> String {
    format!("<!-- {GENERATED_BY_MARKER} -->\n{}", content.into())
}

pub fn stamp_plaintext(content: impl Into<String>) -> String {
    // Plain-text files (LICENSE, NOTICE) carry a `#` comment header. This adds
    // attribution without disturbing license text content checks.
    format!("# {GENERATED_BY_MARKER}\n\n{}", content.into())
}

pub fn core_new(
    core_dir: &Path,
    name: &str,
    class: Option<&str>,
    library: &str,
    language: &str,
    profile: &str,
    axes_override: AxesOverride,
) -> Result<CliOutput, CliError> {
    let (project_class, mut warnings) = match class {
        Some(class) => (parse_project_class(class)?, Vec::new()),
        None => (
            ProjectClass::SimplePortable,
            vec![
                "AF_COMPLEXITY_CLASS_INFERRED: defaulted to simple-portable; run `af project classify` for complex accelerators.".to_string(),
            ],
        ),
    };
    let language = normalize_core_language(language)?;
    let profile = normalize_core_profile(profile)?;
    let mut output = match project_class {
        ProjectClass::SimplePortable if profile == "reset-sync" => {
            core_new_reset_sync(core_dir, name, library, language)?
        }
        ProjectClass::SimplePortable => core_new_stream_ip(core_dir, name, library, language)?,
        ProjectClass::CompositePortable => {
            if profile != "stream-ip" {
                return Err(CliError::new(
                    "AF_CORE_NEW_PROFILE_UNSUPPORTED",
                    format!("profile `{profile}` is unsupported for composite-portable"),
                    "Use --profile stream-ip for composite-portable or --class simple-portable --profile reset-sync for reset synchronizers.",
                    2,
                ));
            }
            core_new_composite_portable(core_dir, name, library, language)?
        }
        ProjectClass::ComplexVendorAware => {
            if profile != "stream-ip" {
                return Err(CliError::new(
                    "AF_CORE_NEW_PROFILE_UNSUPPORTED",
                    format!("profile `{profile}` is unsupported for complex-vendor-aware"),
                    "Use --profile stream-ip for the complex vendor-aware scaffold.",
                    2,
                ));
            }
            core_new_complex_vendor_aware(core_dir, name, library, language)?
        }
        ProjectClass::SystemPlatform | ProjectClass::ProductStack => {
            return Err(CliError::new(
                "AF_COMPLEXITY_CLASS_REQUIRED",
                format!("core new cannot create `{project_class}`"),
                "Use `af project new --class system-platform|product-stack` for system/product templates.",
                2,
            ));
        }
    };
    let development_artifacts = scaffold_core_development_artifacts(core_dir)?;
    if !axes_override.is_empty() {
        apply_axes_override(core_dir, &axes_override)?;
        // Re-load manifest so the JSON output reflects the overridden axes
        // rather than the profile defaults.
        let refreshed = CoreManifest::from_path(core_dir.join("af-core.toml"))?;
        if let Some(object) = output.json.as_object_mut() {
            object.insert("manifest".to_string(), json!(refreshed));
        }
    }
    annotate_core_new_output(&mut output, project_class, &mut warnings);
    if let Some(object) = output.json.as_object_mut() {
        object.insert(
            "development_artifacts".to_string(),
            json!(development_artifacts),
        );
    }
    Ok(output)
}

fn apply_axes_override(core_dir: &Path, override_: &AxesOverride) -> Result<(), CliError> {
    let path = core_dir.join("af-core.toml");
    let raw = fs::read_to_string(&path).map_err(|err| {
        CliError::new(
            "AF_CORE_NEW_AXIS_OVERRIDE_READ_FAILED",
            format!("failed to read `{}`: {err}", path.display()),
            "Check filesystem permissions.",
            5,
        )
    })?;
    let mut value: toml::Value = raw.parse().map_err(|err: toml::de::Error| {
        CliError::new(
            "AF_CORE_NEW_AXIS_OVERRIDE_PARSE_FAILED",
            format!("failed to parse generated `{}`: {err}", path.display()),
            "Regenerate the scaffold; the manifest text is internally produced.",
            5,
        )
    })?;
    let table = value
        .as_table_mut()
        .expect("generated af-core.toml root is a table");
    if let Some(level) = override_.portability_level {
        table.insert(
            "portability_level".to_string(),
            toml::Value::String(level.as_str().to_string()),
        );
    }
    if let Some(priority) = override_.priority {
        table.insert(
            "priority".to_string(),
            toml::Value::String(priority.as_str().to_string()),
        );
    }
    if let Some(maturity) = override_.maturity {
        table.insert(
            "maturity".to_string(),
            toml::Value::String(maturity.as_str().to_string()),
        );
    }
    let serialized = toml::to_string(&value).map_err(|err| {
        CliError::new(
            "AF_CORE_NEW_AXIS_OVERRIDE_SERIALIZE_FAILED",
            format!("failed to serialize updated manifest: {err}"),
            "Report this as a bug; CLI override should not produce non-serializable manifests.",
            5,
        )
    })?;
    fs::write(&path, serialized).map_err(|err| {
        CliError::new(
            "AF_CORE_NEW_AXIS_OVERRIDE_WRITE_FAILED",
            format!("failed to write `{}`: {err}", path.display()),
            "Check filesystem permissions.",
            5,
        )
    })?;
    Ok(())
}
fn normalize_core_language(language: &str) -> Result<&'static str, CliError> {
    match language {
        "verilog" | "verilog-2001" => Ok("verilog-2001"),
        "systemverilog" => Err(CliError::new(
            "AF_CORE_NEW_LANGUAGE_UNSUPPORTED",
            "core new only scaffolds portable Verilog-2001 base cores",
            "Use --language verilog-2001 for generic cores; keep SystemVerilog, vendor primitives, AXI adapters, and PLL logic in optional wrappers outside the base core.",
            2,
        )),
        _ => Err(CliError::new(
            "AF_CORE_NEW_LANGUAGE_UNSUPPORTED",
            format!("core new language `{language}` is unsupported"),
            "Use --language verilog-2001 for the built-in portable scaffold.",
            2,
        )),
    }
}

fn normalize_core_profile(profile: &str) -> Result<&'static str, CliError> {
    match profile {
        "stream-ip" => Ok("stream-ip"),
        "reset-sync" | "atomic-reset-sync" => Ok("reset-sync"),
        _ => Err(CliError::new(
            "AF_CORE_NEW_PROFILE_UNSUPPORTED",
            format!("core new profile `{profile}` is unsupported"),
            "Use --profile stream-ip or --profile reset-sync for the built-in scaffold.",
            2,
        )),
    }
}

fn ensure_portable_core_language(language: &str, profile: &str) -> Result<(), CliError> {
    if language != "verilog-2001" {
        return Err(CliError::new(
            "AF_CORE_NEW_LANGUAGE_UNSUPPORTED",
            format!("core new language `{language}` is unsupported"),
            format!("Use --language verilog-2001 with --profile {profile}."),
            2,
        ));
    }
    Ok(())
}

fn write_generated_core_legal_artifacts(
    core_dir: &Path,
    core_name: &str,
    description: &str,
) -> Result<(), CliError> {
    let license = generated_core_license_text(core_name);
    let commercial = generated_core_commercial_license_text(core_name);
    let notice = generated_core_notice_text(core_name, description);
    write_new_file(&core_dir.join("LICENSE"), license.as_bytes())?;
    write_new_file(
        &core_dir.join("COMMERCIAL-LICENSE.md"),
        commercial.as_bytes(),
    )?;
    write_new_file(&core_dir.join("NOTICE"), notice.as_bytes())?;
    Ok(())
}

