fn annotate_core_new_output(
    output: &mut CliOutput,
    project_class: ProjectClass,
    warnings: &mut Vec<String>,
) {
    warnings.sort();
    warnings.dedup();
    if !warnings.is_empty() {
        output
            .human
            .push_str(&format!("\nwarning: {}", warnings.join("\nwarning: ")));
    }
    if let Some(object) = output.json.as_object_mut() {
        object.insert("project_class".to_string(), json!(project_class));
        object.insert("warnings".to_string(), json!(warnings));
    }
}

fn scaffold_core_development_artifacts(core_dir: &Path) -> Result<Vec<PathBuf>, CliError> {
    let readme = core_dir.join("artifacts/openfpga-ci/README.md");
    let body = stamp_markdown(
        "# Core Development Artifacts\n\nRun `af core tooling . --json` from this core directory, or `af core tooling <core-dir> --json` from a parent repository, to refresh development tool visibility artifacts:\n\n- `reports/core-tooling.json`\n- `reports/core-smt-solvers.json`\n- `reports/core-integration-tools.json`\n- `logs/smt-solvers-tool-versions.txt`\n- `logs/integration-tool-versions.txt`\n\nThese artifacts prove only tool visibility for Boolector, Z3, Yices, Bitwuzla, cvc5, xmllint, FuseSoC and Edalize. They do not prove formal coverage, package semantic completeness, timing closure, CDC/RDC signoff, vendor implementation, or hardware readiness.\n",
    );
    write_new_file(&readme, body.as_bytes())?;
    Ok(vec![readme])
}

fn to_module_ident(name: &str) -> Result<String, CliError> {
    let mut out = String::new();
    for ch in name.chars() {
        if ch.is_ascii_alphanumeric() || ch == '_' {
            out.push(ch);
        } else if matches!(ch, '-' | '.') {
            out.push('_');
        } else {
            return Err(CliError::new(
                "AF_IDENTIFIER_INVALID",
                format!("unsupported character `{ch}` in core name `{name}`"),
                "Use letters, digits, underscore, dash, or dot.",
                2,
            ));
        }
    }
    let Some(first) = out.chars().next() else {
        return Err(CliError::new(
            "AF_IDENTIFIER_INVALID",
            "core name must not be empty",
            "Provide a non-empty core name.",
            2,
        ));
    };
    if !(first.is_ascii_alphabetic() || first == '_') {
        return Err(CliError::new(
            "AF_IDENTIFIER_INVALID",
            format!("core name `{name}` must start with a letter or underscore"),
            "Use a Verilog-compatible module name.",
            2,
        ));
    }
    Ok(out)
}
